import{_ as a,H as d,f as e,i as r}from"./chunks/framework.DLd0CbzH.js";const b=JSON.parse('{"title":"API 参考","description":"","frontmatter":{},"headers":[],"relativePath":"api/index.md","filePath":"api/index.md","lastUpdated":1780150416000}'),o={name:"api/index.md"};function i(h,t,l,s,c,n){return d(),e("div",null,[...t[0]||(t[0]=[r('<h1 id="api-参考" tabindex="-1">API 参考 <a class="header-anchor" href="#api-参考" aria-label="Permalink to &quot;API 参考&quot;">​</a></h1><p>欢迎使用 Ay 开放平台 API。所有接口均通过 <code>https://api.undz.cn</code> 或 <code>https://api.io.hb.cn</code> 提供，无需认证（部分管理接口除外），开箱即用。</p><h2 id="可用-api-分组" tabindex="-1">可用 API 分组 <a class="header-anchor" href="#可用-api-分组" aria-label="Permalink to &quot;可用 API 分组&quot;">​</a></h2><h3 id="📍-ip-归属地" tabindex="-1">📍 IP 归属地 <a class="header-anchor" href="#📍-ip-归属地" aria-label="Permalink to &quot;📍 IP 归属地&quot;">​</a></h3><table tabindex="0"><thead><tr><th>方法</th><th>路径</th><th>描述</th></tr></thead><tbody><tr><td>GET</td><td><code>/ip</code></td><td>获取当前请求的 IP 信息（含地理位置、运营商、TLS 信息等）</td></tr></tbody></table><p><strong>使用示例</strong>：<code>curl https://api.undz.cn/ip</code></p><p>详见 <a href="/api/ip.html">IP 归属地</a> 文档。</p><hr><h3 id="👥-添加-qq-好友" tabindex="-1">👥 添加 QQ 好友 <a class="header-anchor" href="#👥-添加-qq-好友" aria-label="Permalink to &quot;👥 添加 QQ 好友&quot;">​</a></h3><table tabindex="0"><thead><tr><th>方法</th><th>路径</th><th>描述</th></tr></thead><tbody><tr><td>GET</td><td><code>/addqq</code></td><td>生成 QQ 好友添加链接，移动端一键拉起 QQ</td></tr></tbody></table><p><strong>参数</strong>：<code>uid</code>（QQ 号） <strong>示例</strong>：<code>https://api.undz.cn/addqq?uid=10000</code></p><h2 id="详见-添加-qq-好友-文档。" tabindex="-1">详见 <a href="/api/add-qq-friend.html">添加 QQ 好友</a> 文档。 <a class="header-anchor" href="#详见-添加-qq-好友-文档。" aria-label="Permalink to &quot;详见 [添加 QQ 好友](/api/add-qq-friend) 文档。&quot;">​</a></h2><h3 id="🔗-短链服务" tabindex="-1">🔗 短链服务 <a class="header-anchor" href="#🔗-短链服务" aria-label="Permalink to &quot;🔗 短链服务&quot;">​</a></h3><table tabindex="0"><thead><tr><th>方法</th><th>路径</th><th>描述</th></tr></thead><tbody><tr><td>GET</td><td><code>/go/parse</code></td><td>解析短链码，返回原始 URL</td></tr><tr><td>POST</td><td><code>/go/addlink</code></td><td>创建短链（需管理员密钥）</td></tr></tbody></table><p>详见 <a href="/api/short-link/short-link-resolve.html">短链解析</a> 和 <a href="/api/short-link/short-link-create.html">创建短链</a> 文档。</p><hr><h3 id="📝-文本分享-aypass" tabindex="-1">📝 文本分享 (AyPass) <a class="header-anchor" href="#📝-文本分享-aypass" aria-label="Permalink to &quot;📝 文本分享 (AyPass)&quot;">​</a></h3><table tabindex="0"><thead><tr><th>方法</th><th>路径</th><th>描述</th></tr></thead><tbody><tr><td>POST</td><td><code>/api/sf/v1/save</code></td><td>保存文本，自动生成唯一 ID</td></tr><tr><td>POST</td><td><code>/api/sf/v1/delete</code></td><td>删除已保存的文本</td></tr><tr><td>GET</td><td><code>/sf/{name}</code></td><td>获取原始文本</td></tr></tbody></table><p>详见 <a href="/api/pass-text/pass-text-save.html">文本分享</a> 和 <a href="/api/pass-text/pass-text-delete.html">删除文本</a>。</p><hr><h3 id="📧-邮件验证码-暂停" tabindex="-1">📧 邮件验证码（暂停） <a class="header-anchor" href="#📧-邮件验证码-暂停" aria-label="Permalink to &quot;📧 邮件验证码（暂停）&quot;">​</a></h3><table tabindex="0"><thead><tr><th>方法</th><th>路径</th><th>描述</th></tr></thead><tbody><tr><td>POST</td><td><code>/api/verifymail/v1/send</code></td><td>发送验证码（目前暂停）</td></tr><tr><td>POST</td><td><code>/api/verifymail/v1/verify</code></td><td>校验验证码</td></tr></tbody></table><p>详见 <a href="/api/verifymail.html">邮件验证码</a> 文档。</p><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p>当前服务暂停</p></div><hr><h3 id="💬-聊天室相关" tabindex="-1">💬 聊天室相关 <a class="header-anchor" href="#💬-聊天室相关" aria-label="Permalink to &quot;💬 聊天室相关&quot;">​</a></h3><table tabindex="0"><thead><tr><th>方法</th><th>路径</th><th>描述</th></tr></thead><tbody><tr><td>GET</td><td><code>/chat</code></td><td>进入聊天室前端页面</td></tr><tr><td>GET</td><td><code>/poll</code></td><td>轮询新消息</td></tr><tr><td>GET</td><td><code>/send</code></td><td>发送消息</td></tr><tr><td>GET</td><td><code>/create</code></td><td>创建自定义房间账号</td></tr></tbody></table><p>详见 <a href="/api/chatroom.html">聊天室</a> 文档。</p><hr><h3 id="🎮-crossfire-ys-游戏云端" tabindex="-1">🎮 Crossfire: Ys 游戏云端 <a class="header-anchor" href="#🎮-crossfire-ys-游戏云端" aria-label="Permalink to &quot;🎮 Crossfire: Ys 游戏云端&quot;">​</a></h3><table tabindex="0"><thead><tr><th>方法</th><th>路径</th><th>描述</th></tr></thead><tbody><tr><td>POST</td><td><code>/api/crossfire/v1/account/create</code></td><td>注册账号</td></tr><tr><td>POST</td><td><code>/api/crossfire/v1/account/login</code></td><td>登录获取 token</td></tr><tr><td>POST</td><td><code>/api/crossfire/v1/bag/get</code></td><td>获取背包数据</td></tr><tr><td>POST</td><td><code>/api/crossfire/v1/bag/push</code></td><td>更新背包数据</td></tr></tbody></table><p>详见 <a href="/api/crossfire.html">Crossfire: Ys</a> 文档。</p><hr><h3 id="🌐-网络代理-需授权" tabindex="-1">🌐 网络代理（需授权） <a class="header-anchor" href="#🌐-网络代理-需授权" aria-label="Permalink to &quot;🌐 网络代理（需授权）&quot;">​</a></h3><table tabindex="0"><thead><tr><th>方法</th><th>路径</th><th>描述</th></tr></thead><tbody><tr><td>GET</td><td><code>/proxy/*</code></td><td>通用代理（需认证）</td></tr><tr><td>GET</td><td><code>/gh/*</code></td><td>GitHub 专用代理（无需认证，但只能访问GitHub及其相关域名）</td></tr><tr><td>GET</td><td><code>/auth-proxy</code></td><td>获取代理授权（需密钥）</td></tr></tbody></table><p>详见 <a href="/api/proxy.html">网络代理</a> 文档。</p><p>通用代理功能仅供授权用户使用。 如需使用通用代理，请与我联系：</p><ul><li>通过 <a href="https://space.bilibili.com/3494370328185235" target="_blank" rel="noreferrer">BiliBili</a>（推荐）</li><li>通过 GitHub <a href="https://github.com/AeYunDian/open_platform/issues" target="_blank" rel="noreferrer">Issues</a></li><li>发送邮件至 <a href="mailto:admin@exm.undz.cn" target="_blank" rel="noreferrer">admin@exm.undz.cn</a></li></ul><hr><h2 id="基础信息" tabindex="-1">基础信息 <a class="header-anchor" href="#基础信息" aria-label="Permalink to &quot;基础信息&quot;">​</a></h2><ul><li><strong>基础 URL</strong>：<code>https://api.undz.cn</code>（也支持 <code>https://api.io.hb.cn</code>）</li><li><strong>请求格式</strong>：大部分接口返回 JSON，具体见各接口文档。</li><li><strong>认证方式</strong>：目前公开 API 无需认证。涉及写入/删除的接口需提供 <code>key</code> 参数（与管理员共享密钥）。</li><li><strong>频率限制</strong>：无硬性限制，请合理使用。</li></ul><h2 id="更多资源" tabindex="-1">更多资源 <a class="header-anchor" href="#更多资源" aria-label="Permalink to &quot;更多资源&quot;">​</a></h2><ul><li><a href="/guide/">快速开始</a> – 从零调用第一个 API</li><li><a href="/guide/faq.html">常见问题</a> – 解答使用中的疑问</li><li><a href="https://github.com/AeYunDian/api" target="_blank" rel="noreferrer">GitHub 仓库</a> – 开源代码与问题反馈</li></ul><blockquote><p>各 API 详细参数、响应示例请点击上方链接查看独立文档。</p></blockquote>',44)])])}const u=a(o,[["render",i]]);export{b as __pageData,u as default};
